//! WASM AOT emitter correctness — the checked-in walker/AOT
//! differential discipline for the wasm lane (the sibling of the
//! numeric-loop parity harness inside aot_c.rs).
//!
//! Modules are executed under Node — the same V8 engine
//! `gnosis/src/wasm-execution-bridge.ts` runs on — driving the exact
//! scalar-v1 / json-v1 host sequences the bridge uses. Scalar results
//! compare by f64 BIT PATTERN (no decimal-formatting games); declines
//! assert the trap (exit 3 from the harness). Expected values for the
//! full-domain bitwise family are computed in Rust with the walker's
//! own semantics (saturating casts, masked shifts), because the wasm
//! lane intentionally answers where the C lane must decline.
//!
//! Tests are skipped politely when `node` is unavailable, mirroring the
//! `cc_available()` convention in aot_c.rs.

use std::fs;
use std::path::Path;
use std::process::Command;

use gnosis_polyglot::aot_wasm::{
    emit_wasm_for_export, lookup_cached_wasm, numeric_loop_wasm_bytes, prepare_cached_wasm,
    supports_wasm_for_export,
};

const HARNESS_JS: &str = r#"
const fs = require('fs');
const [,, wasmPath, abi, inputJson] = process.argv;
const bytes = fs.readFileSync(wasmPath);
const mod = new WebAssembly.Module(bytes);
if (WebAssembly.Module.imports(mod).length !== 0) {
  console.error('emitted module must have an empty import section');
  process.exit(4);
}
const inst = new WebAssembly.Instance(mod, {});
const ex = inst.exports;
try {
  if (abi === 'scalar-v1') {
    const args = JSON.parse(inputJson);
    const r = ex.main(...args);
    const buf = new ArrayBuffer(8);
    new Float64Array(buf)[0] = r;
    process.stdout.write(new BigUint64Array(buf)[0].toString(16));
  } else {
    const input = new TextEncoder().encode(inputJson);
    const p = ex.gnosis_alloc(input.length);
    new Uint8Array(ex.memory.buffer, p, input.length).set(input);
    const o = ex.main(p, input.length);
    const n = ex.gnosis_result_len();
    const text = new TextDecoder('utf-8', { fatal: true })
      .decode(new Uint8Array(ex.memory.buffer, o, n));
    JSON.parse(text); // json-v1 output must be valid JSON
    process.stdout.write(text);
  }
} catch (e) {
  if (e instanceof WebAssembly.RuntimeError) process.exit(3);
  throw e;
}
"#;

fn node_available() -> bool {
    Command::new("node")
        .arg("--version")
        .output()
        .map(|out| out.status.success())
        .unwrap_or(false)
}

struct Harness {
    dir: tempfile::TempDir,
}

impl Harness {
    fn new() -> Self {
        let dir = tempfile::tempdir().expect("tempdir");
        fs::write(dir.path().join("harness.js"), HARNESS_JS).expect("write harness");
        Harness { dir }
    }

    fn run(&self, wasm: &[u8], abi: &str, input: &str) -> (Option<String>, Option<i32>) {
        let wasm_path = self.dir.path().join("module.wasm");
        fs::write(&wasm_path, wasm).expect("write module");
        let output = Command::new("node")
            .arg(self.dir.path().join("harness.js"))
            .arg(&wasm_path)
            .arg(abi)
            .arg(input)
            .output()
            .expect("node harness runs");
        let stdout = if output.status.success() {
            Some(String::from_utf8_lossy(&output.stdout).trim().to_string())
        } else {
            None
        };
        if !output.status.success() && output.status.code() != Some(3) {
            panic!(
                "harness failed unexpectedly (code {:?}):\n{}",
                output.status.code(),
                String::from_utf8_lossy(&output.stderr)
            );
        }
        (stdout, output.status.code())
    }

    /// scalar-v1: assert the module answers with EXACTLY this f64.
    fn assert_scalar(&self, wasm: &[u8], args: &str, expected: f64) {
        let (out, code) = self.run(wasm, "scalar-v1", args);
        assert_eq!(code, Some(0), "scalar run should answer for args {args}");
        assert_eq!(
            out.as_deref(),
            Some(format!("{:x}", expected.to_bits()).as_str()),
            "f64 bit pattern must match walker semantics for args {args} (expected {expected})"
        );
    }

    /// scalar-v1: assert the module DECLINES (traps) on these args.
    fn assert_scalar_decline(&self, wasm: &[u8], args: &str) {
        let (out, code) = self.run(wasm, "scalar-v1", args);
        assert_eq!(out, None, "decline must not answer for args {args}");
        assert_eq!(code, Some(3), "decline is a trap for args {args}");
    }

    fn assert_json(&self, wasm: &[u8], input: &str, expected: &str) {
        let (out, code) = self.run(wasm, "json-v1", input);
        assert_eq!(code, Some(0), "json run should answer for input {input}");
        assert_eq!(out.as_deref(), Some(expected));
    }

    fn assert_json_decline(&self, wasm: &[u8], input: &str) {
        let (out, code) = self.run(wasm, "json-v1", input);
        assert_eq!(out, None, "decline must not answer for input {input}");
        assert_eq!(code, Some(3), "decline is a trap for input {input}");
    }
}

fn numeric(source: &str) -> Vec<u8> {
    numeric_loop_wasm_bytes(source, "main").expect("program is in the certified class")
}

fn emit_fixture(relative_fixture_path: &str) -> (Vec<u8>, String) {
    let manifest_dir = Path::new(env!("CARGO_MANIFEST_DIR"));
    let fixture_path = manifest_dir.join(relative_fixture_path);
    let source = fs::read_to_string(&fixture_path).expect("fixture source should be readable");
    let scan =
        gnosis_polyglot::parse_and_extract_orchestration(&source, &fixture_path.to_string_lossy())
            .expect("fixture should extract");
    let emitted = emit_wasm_for_export(&scan, &source, "app").expect("fixture should emit wasm");
    (emitted.bytes, emitted.manifest.abi.to_string())
}

