// ── Manifest / cache / fail-closed plumbing ─────────────────────────

#[test]
fn manifest_fields_and_cache_roundtrip() {
    let manifest_dir = Path::new(env!("CARGO_MANIFEST_DIR"));
    let fixture_path = manifest_dir.join("../gnode/benchmarks/fib.ts");
    let source = fs::read_to_string(&fixture_path).expect("fixture source should be readable");
    let scan =
        gnosis_polyglot::parse_and_extract_orchestration(&source, &fixture_path.to_string_lossy())
            .expect("fixture should extract");

    assert!(supports_wasm_for_export(&scan, &source, "app"));
    let emitted = emit_wasm_for_export(&scan, &source, "app").expect("emits");
    let manifest = &emitted.manifest;
    assert_eq!(manifest.artifact_version, "betti-wasm/1");
    assert_eq!(manifest.abi, "json-v1");
    assert_eq!(manifest.tier, "certified-direct");
    assert_eq!(manifest.certified_class, "fibonacci");
    assert_eq!(manifest.decline_semantics, "trap");
    assert!(manifest.imports.is_empty());
    assert_eq!(manifest.artifact_id.len(), 16);
    assert_eq!(manifest.sha256.len(), 64);
    assert!(manifest.byte_length > 0);
    // Determinism: same topology → byte-identical artifact.
    let again = emit_wasm_for_export(&scan, &source, "app").expect("emits again");
    assert_eq!(emitted.bytes, again.bytes);

    let temp_dir = tempfile::tempdir().expect("tempdir");
    let first = prepare_cached_wasm(&scan, &source, "app", temp_dir.path()).expect("first");
    let second = prepare_cached_wasm(&scan, &source, "app", temp_dir.path()).expect("second");
    assert!(!first.cache_hit);
    assert!(second.cache_hit);
    assert_eq!(first.fingerprint, second.fingerprint);
    assert!(second.wasm_path.exists());
    assert!(second.manifest_path.exists());

    let hit = lookup_cached_wasm(
        &fixture_path.to_string_lossy(),
        &source,
        "app",
        temp_dir.path(),
    )
    .expect("source-key lookup hits");
    assert_eq!(hit.fingerprint, first.fingerprint);
}

#[test]
fn unsupported_topology_fails_closed() {
    let source = "export function app(input) { return fetch(input.url); }\n";
    let scan = gnosis_polyglot::parse_and_extract_orchestration(source, "unsupported.ts")
        .expect("extracts");
    assert!(!supports_wasm_for_export(&scan, source, "app"));
    let error = emit_wasm_for_export(&scan, source, "app").expect_err("must fail closed");
    assert!(error.to_string().contains("this topology is in neither"));
}

// ── Tier A × Tier B cross-check ─────────────────────────────────────
//
// Two unrelated compilation pipelines — direct wasm-encoder emission
// (aot_wasm) and clang-compiled freestanding C (aot_wasm_c) — must
// produce BIT-IDENTICAL f64 answers on inputs inside both lanes'
// answer domains, and agree on declines where their domains coincide.
// Inputs stay inside the C lane's narrower fences (integral bitwise
// operands < 2^32, integral %), since Tier A intentionally answers a
// wider domain.

#[test]
fn tier_a_and_tier_b_agree_bit_for_bit() {
    if !node_available() {
        return;
    }
    let Some(_) = gnosis_polyglot::aot_wasm_c::wasm_clang() else {
        eprintln!("skipping tier A/B cross-check: no wasm32-capable clang");
        return;
    };

    let programs: &[(&str, &[&str])] = &[
        (
            "export function main(n) {\n  let s = 0;\n  for (let i = 0; i < n; i++) { s = s + i; }\n  return s;\n}\n",
            &["[900]", "[2000000]", "[0]"],
        ),
        (
            "export function main(n) {\n  let h = [0, 0, 0, 0, 0];\n  for (let i = 0; i < n; i++) { h[i % 5] += 1; }\n  let s = 0;\n  for (let j = 0; j < h.length; j++) { s += h[j] * (j + 1); }\n  return s;\n}\n",
            &["[10]", "[1000000]"],
        ),
        (
            "export function main(n) {\n  return Math.floor(n / 2) + Math.max(1, 2, 3) + Math.abs(0 - 4) + Math.min(9, 5) + Math.round(n / 4);\n}\n",
            &["[9]", "[10]", "[2]"],
        ),
        (
            "export function main(n) {\n  return (n << 2) + (n >> 1) + (n >>> 1) + (n & 5) + (n | 3) + (n ^ 9);\n}\n",
            &["[66]", "[7]", "[1024]"],
        ),
        (
            "export function main(n) { return n / 4; }\n",
            &["[2]", "[10]", "[-6]"],
        ),
    ];

    let h = Harness::new();
    for (source, inputs) in programs {
        let tier_a = numeric_loop_wasm_bytes(source, "main").expect("tier A emits");
        let tier_b = gnosis_polyglot::aot_wasm_c::compile_wasm_via_c(source, "main")
            .expect("tier B compiles");
        for input in *inputs {
            let (out_a, code_a) = h.run(&tier_a, "scalar-v1", input);
            let (out_b, code_b) = h.run(&tier_b, "scalar-v1", input);
            assert_eq!(
                (out_a.as_deref(), code_a),
                (out_b.as_deref(), code_b),
                "tier A and tier B diverged for {input} on:\n{source}"
            );
        }
    }

    // Decline agreement where the domains coincide: OOB array reads.
    let oob = "export function main(n) {\n  let h = [1, 2, 3];\n  return h[n];\n}\n";
    let tier_a = numeric_loop_wasm_bytes(oob, "main").expect("tier A emits");
    let tier_b =
        gnosis_polyglot::aot_wasm_c::compile_wasm_via_c(oob, "main").expect("tier B compiles");
    for input in ["[7]", "[-1]", "[0.5]"] {
        assert_eq!(h.run(&tier_a, "scalar-v1", input).1, Some(3));
        assert_eq!(h.run(&tier_b, "scalar-v1", input).1, Some(3));
    }
}

// ── Certified scalar-string class (json-v1) ─────────────────────────
//
// Wave-2 A1: the string-capable certified class. Same differential
// discipline as above — every answer is compared against the exact JS
// value V8 would produce, and every input the module cannot answer
// bit-identically DECLINES via trap (exit 3). Appended as its own
// section; the earlier sections are shared with other agents.

fn string_class(source: &str) -> Vec<u8> {
    gnosis_polyglot::aot_wasm::string_class_wasm_bytes(source, "main")
        .expect("program is in the certified scalar-string class")
}

#[test]
fn string_class_parity_template_field() {
    if !node_available() {
        eprintln!("skipping scalar-string parity test because node is not available");
        return;
    }
    let wasm = string_class("export function main(input) { return `hello:${input.name}!`; }\n");
    let h = Harness::new();
    h.assert_json(&wasm, r#"{"name":"ada"}"#, r#""hello:ada!""#);
    h.assert_json(&wasm, r#"{"name": "grace"}"#, r#""hello:grace!""#); // ws after colon
    h.assert_json(&wasm, r#"{"name":""}"#, r#""hello:!""#);
    // Escaped input strings are walker jurisdiction → decline.
    h.assert_json_decline(&wasm, r#"{"name":"a\"b"}"#);
    h.assert_json_decline(&wasm, r#"{"name":"a\\b"}"#);
    // Missing field → decline.
    h.assert_json_decline(&wasm, r#"{"nope":1}"#);
}

#[test]
fn string_class_parity_concat_two_fields() {
    if !node_available() {
        return;
    }
    let wasm =
        string_class("export function main(input) { return input.first + \":\" + input.last; }\n");
    let h = Harness::new();
    h.assert_json(
        &wasm,
        r#"{"first":"ada","last":"lovelace"}"#,
        r#""ada:lovelace""#,
    );
    // Polymorphic concat fields stringify JSON integers exactly like
    // JS `+` (number coerces to digits).
    h.assert_json(&wasm, r#"{"first":"v","last":42}"#, r#""v:42""#);
    h.assert_json_decline(&wasm, r#"{"first":"only"}"#);
}

#[test]
fn string_class_parity_number_in_template() {
    if !node_available() {
        return;
    }
    let h = Harness::new();
    let wasm = string_class("export function main(input) { return `n is ${input.n}`; }\n");
    h.assert_json(&wasm, r#"{"n":42}"#, r#""n is 42""#);
    h.assert_json(&wasm, r#"{"n":-7}"#, r#""n is -7""#);
    h.assert_json(&wasm, r#"{"n":0}"#, r#""n is 0""#);
    // A string in the same slot is also exactly JS templating.
    h.assert_json(&wasm, r#"{"n":"many"}"#, r#""n is many""#);
    // Non-integral numbers in a template DECLINE (digit formatting is
    // the fibonacci convention; float formatting is walker turf).
    h.assert_json_decline(&wasm, r#"{"n":4.5}"#);
    h.assert_json_decline(&wasm, r#"{"n":1e3}"#);
    // Invalid-JSON leading zeros decline rather than mis-answer.
    h.assert_json_decline(&wasm, r#"{"n":042}"#);

    // Non-integral produced by ARITHMETIC inside a template declines
    // at the format helper, not the parser.
    let half = string_class("export function main(input) { return `half:${input.n / 2}`; }\n");
    h.assert_json(&half, r#"{"n":4}"#, r#""half:2""#);
    h.assert_json_decline(&half, r#"{"n":5}"#);
}

#[test]
fn string_class_parity_numeric_return() {
    if !node_available() {
        return;
    }
    let h = Harness::new();
    let wasm = string_class("export function main(input) { return input.n * 2 + 1; }\n");
    h.assert_json(&wasm, r#"{"n":20}"#, "41");
    h.assert_json(&wasm, r#"{"n":0}"#, "1");
    h.assert_json(&wasm, r#"{"n":-3}"#, "-5"); // JSON numbers may be negative
    // Non-integral input field → decline (strict integer parse).
    h.assert_json_decline(&wasm, r#"{"n":20.5}"#);
    // Non-integral RESULT → decline at the digit formatter.
    let frac = string_class("export function main(input) { return input.n / 2; }\n");
    h.assert_json(&frac, r#"{"n":10}"#, "5");
    h.assert_json_decline(&frac, r#"{"n":5}"#);
    // A string where a number is demanded → decline.
    h.assert_json_decline(&wasm, r#"{"n":"str"}"#);
}

#[test]
fn string_class_parity_if_else_and_string_equality() {
    if !node_available() {
        return;
    }
    let h = Harness::new();
    let wasm = string_class(
        "export function main(input) { if (input.role === \"admin\") { return \"yes\"; } else { return \"no:\" + input.role; } }\n",
    );
    h.assert_json(&wasm, r#"{"role":"admin"}"#, r#""yes""#);
    h.assert_json(&wasm, r#"{"role":"user"}"#, r#""no:user""#);
    // Equality operands are STRICT string reads: a JSON number there
    // declines (byte-comparing digits would diverge from JS ===).
    h.assert_json_decline(&wasm, r#"{"role":5}"#);

    let neq = string_class(
        "export function main(input) { if (input.a !== input.b) { return \"diff\" } return \"same\"; }\n",
    );
    h.assert_json(&neq, r#"{"a":"x","b":"y"}"#, r#""diff""#);
    h.assert_json(&neq, r#"{"a":"x","b":"x"}"#, r#""same""#);

    // Numeric truthiness conditions + string locals through branches.
    let branchy = string_class(
        "export function main(input) { let tag = \"lo\"; if (input.n > 9) { tag = `hi:${input.n}`; } return tag; }\n",
    );
    h.assert_json(&branchy, r#"{"n":12}"#, r#""hi:12""#);
    h.assert_json(&branchy, r#"{"n":3}"#, r#""lo""#);
}

#[test]
fn string_class_parity_mixed_numeric_subset() {
    if !node_available() {
        return;
    }
    let h = Harness::new();
    // Numeric fields, Math intrinsics, %, and locals feeding a template.
    let wasm = string_class(
        "export function main(input) { let k = Math.max(input.a, input.b) % 5; return `k=${k}`; }\n",
    );
    h.assert_json(&wasm, r#"{"a":12,"b":8}"#, r#""k=2""#);
    h.assert_json(&wasm, r#"{"a":3,"b":9}"#, r#""k=4""#);

    // Boolean-producing string equality inside numeric expressions.
    let as_num = string_class(
        "export function main(input) { let hit = input.tag === \"x\"; return hit * 10 + 1; }\n",
    );
    h.assert_json(&as_num, r#"{"tag":"x"}"#, "11");
    h.assert_json(&as_num, r#"{"tag":"y"}"#, "1");
}

#[test]
fn string_class_manifest_and_fail_closed() {
    let source = "export function main(input) { return `hello:${input.name}!`; }\n";
    let scan = gnosis_polyglot::parse_and_extract_orchestration(source, "string-class.ts")
        .expect("extracts");
    assert!(supports_wasm_for_export(&scan, source, "main"));
    let emitted = emit_wasm_for_export(&scan, source, "main").expect("emits");
    assert_eq!(emitted.manifest.certified_class, "scalar-string");
    assert_eq!(emitted.manifest.abi, "json-v1");
    assert_eq!(emitted.manifest.tier, "certified-direct");
    assert_eq!(emitted.manifest.decline_semantics, "trap");
    assert!(emitted.manifest.imports.is_empty());
    // Determinism through the full manifest path too.
    let again = emit_wasm_for_export(&scan, source, "main").expect("emits again");
    assert_eq!(emitted.bytes, again.bytes);

    // Outside the class: .length / methods / loops fail closed through
    // the public surface.
    for source in [
        "export function main(input) { return input.name.length; }\n",
        "export function main(input) { return input.name.slice(1); }\n",
        "export function main(input) { let s = \"\"; for (let i = 0; i < 3; i++) { s = s + \"x\"; } return s; }\n",
    ] {
        let scan = gnosis_polyglot::parse_and_extract_orchestration(source, "string-class.ts")
            .expect("extracts");
        assert!(
            !supports_wasm_for_export(&scan, source, "main"),
            "must not claim: {source}"
        );
        assert!(emit_wasm_for_export(&scan, source, "main").is_err());
    }
}

// ── Bootstrap smoke (Wave A4) — the compiler compiles a piece of itself ─

/// Bootstrap smoke: a REAL Betty-compiler helper — `invertCoupling` from
/// `open-source/gnosis/src/betti/s-duality-router.ts` (the S-duality
/// inversion g → 1/g) — read from its ORIGINAL source file, claimed by the
/// Tier-A scalar-v1 numeric class as-is, and executed with parity against
/// the walker/gnexec semantics.
///
/// Pinned values are gnexec-verified (2026-07-03, debug gnexec):
/// `gnexec ../src/betti/s-duality-router.ts --export invertCoupling
///  --input-json '8'` → `0.125` (the wasm answers bit-identically).
///
/// HONEST SEAM, pinned rather than hidden: at `g = 0` the source returns
/// the global `Infinity`, which the wasm lane compiles to f64 +inf — but
/// the gnexec interpreter walker currently resolves the bare `Infinity`
/// identifier to a module shim object (`{"__module_shim__":true,
/// "__name__":"Infinity"}`), so the two lanes DISAGREE at that one input.
/// The wasm answer matches real JavaScript semantics; the walker's shim is
/// the divergent side. We pin the wasm behavior here and deliberately do
/// NOT claim walker parity at g = 0 (decline-not-divergence review target
/// for the walker, not the emitter). Corpus row:
/// `gnode/benchmarks/betti-invert-coupling.ts`.
#[test]
fn bootstrap_smoke_betti_invert_coupling() {
    if !node_available() {
        eprintln!("skipping wasm parity test because node is not available");
        return;
    }
    let betti_path = Path::new(env!("CARGO_MANIFEST_DIR"))
        .join("../src/betti/s-duality-router.ts");
    let source = fs::read_to_string(&betti_path)
        .expect("betti compiler source s-duality-router.ts should be readable");
    let scan = gnosis_polyglot::parse_and_extract_orchestration(
        &source,
        &betti_path.to_string_lossy(),
    )
    .expect("betti compiler source should extract");

    assert!(
        supports_wasm_for_export(&scan, &source, "invertCoupling"),
        "Tier A should claim the betti invertCoupling helper as-is"
    );
    let emitted =
        emit_wasm_for_export(&scan, &source, "invertCoupling").expect("emits wasm");
    assert_eq!(emitted.manifest.abi, "scalar-v1");
    assert_eq!(emitted.manifest.tier, "certified-direct");
    assert!(emitted.manifest.imports.is_empty());
    assert_eq!(emitted.manifest.function_name, "invertCoupling");

    let h = Harness::new();
    // gnexec-verified parity points (1/g branch).
    h.assert_scalar(&emitted.bytes, "[8]", 0.125);
    h.assert_scalar(&emitted.bytes, "[-4]", -0.25);
    h.assert_scalar(&emitted.bytes, "[0.5]", 2.0);
    // The pinned seam: wasm answers +inf (JS semantics); see doc comment.
    h.assert_scalar(&emitted.bytes, "[0]", f64::INFINITY);
}
